import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { registerAPI } from '../../api';
import { useAuth } from '../../context/AuthContext';
import './Auth.css';

export default function SignupPage() {
  const [form, setForm] = useState({ name: '', email: '', password: '', phone: '' });
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => setForm(p => ({ ...p, [e.target.name]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (form.password.length < 6) return toast.error('Password must be at least 6 characters');
    try {
      setLoading(true);
      const res = await registerAPI(form);
      login(res.data.user, res.data.token);
      toast.success(`Welcome to Luxe Library, ${res.data.user.name}!`);
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth">
      <div className="auth__panel">
        <div className="auth__panel-bg" />
        <div className="auth__panel-content">
          <Link to="/" className="auth__logo">
            <span className="auth__logo-star">✦</span>
            LUXE LIBRARY
          </Link>
          <div className="auth__panel-quote">
            <p>"The more that you read, the more things you will know. The more that you learn, the more places you'll go."</p>
            <span>— Dr. Seuss</span>
          </div>
          <div className="auth__panel-deco">
            {['🌟', '📚', '🎓', '🌍'].map((e, i) => (
              <div key={i} className="auth__panel-icon" style={{ '--i': i }}>{e}</div>
            ))}
          </div>
        </div>
      </div>

      <div className="auth__form-panel">
        <div className="auth__form-wrap page-enter">
          <div className="auth__header">
            <p className="auth__sub">Start your journey</p>
            <h1 className="auth__title">Create Account</h1>
            <p className="auth__desc">Join Luxe Library and unlock access to our premium curated collection.</p>
          </div>

          <form onSubmit={handleSubmit} className="auth__form">
            <div className="auth__row">
              <div className="auth__field">
                <label className="auth__label">Full Name *</label>
                <input className="auth__input" type="text" name="name" value={form.name} onChange={handleChange} placeholder="Your full name" required />
              </div>
              <div className="auth__field">
                <label className="auth__label">Phone</label>
                <input className="auth__input" type="tel" name="phone" value={form.phone} onChange={handleChange} placeholder="+91 98765 43210" />
              </div>
            </div>

            <div className="auth__field">
              <label className="auth__label">Email Address *</label>
              <input className="auth__input" type="email" name="email" value={form.email} onChange={handleChange} placeholder="your@email.com" required />
            </div>

            <div className="auth__field">
              <label className="auth__label">Password *</label>
              <div className="auth__input-wrap">
                <input
                  className="auth__input"
                  type={showPass ? 'text' : 'password'}
                  name="password"
                  value={form.password}
                  onChange={handleChange}
                  placeholder="Min. 6 characters"
                  required
                />
                <button type="button" className="auth__eye" onClick={() => setShowPass(!showPass)}>
                  {showPass ? '🙈' : '👁️'}
                </button>
              </div>
              {form.password && (
                <div className="auth__strength">
                  <div className="auth__strength-bar" style={{ width: form.password.length >= 8 ? '100%' : form.password.length >= 6 ? '60%' : '30%', background: form.password.length >= 8 ? 'var(--green)' : form.password.length >= 6 ? 'var(--gold)' : 'var(--red)' }} />
                </div>
              )}
            </div>

            <div className="auth__terms">
              <input type="checkbox" id="terms" required />
              <label htmlFor="terms">I agree to the <span className="auth__switch-link">Terms of Service</span> and <span className="auth__switch-link">Privacy Policy</span></label>
            </div>

            <button type="submit" className="auth__submit" disabled={loading}>
              {loading ? <span className="auth__spinner" /> : 'Create Account'}
            </button>
          </form>

          <p className="auth__switch">
            Already have an account?{' '}
            <Link to="/login" className="auth__switch-link">Sign In →</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
